// UserSessionManager tracks user sessions to prevent cardinality explosion
type UserSessionManager struct {
	sessions map[string]*session
	mu       sync.RWMutex
}

type session struct {
	userID    string
	lastSeen  time.Time
	active    bool
	requests  int64
}

var sessionManager = &UserSessionManager{
	sessions: make(map[string]*session),
}

func (usm *UserSessionManager) trackUser(userID string) {
	usm.mu.Lock()
	defer usm.mu.Unlock()

	if sess, exists := usm.sessions[userID]; exists {
		sess.lastSeen = time.Now()
		sess.requests++
	} else {
		usm.sessions[userID] = &session{
			userID:   userID,
			lastSeen: time.Now(),
			active:   true,
			requests: 1,
		}
		userSessions.WithLabelValues(userID).Inc()
	}
}

func (usm *UserSessionManager) cleanupInactiveSessions() {
	usm.mu.Lock()
	defer usm.mu.Unlock()

	now := time.Now()
	for userID, sess := range usm.sessions {
		if now.Sub(sess.lastSeen) > 30*time.Minute {
			delete(usm.sessions, userID)
			userSessions.WithLabelValues(userID).Dec()
		}
	}
}

func (usm *UserSessionManager) getActiveUserCount() int {
	usm.mu.RLock()
	defer usm.mu.RUnlock()
	return len(usm.sessions)
}

// RateLimiter prevents excessive cardinality
type RateLimiter struct {
	limits map[string]int64
	mu     sync.RWMutex
}

var rateLimiter = &RateLimiter{
	limits: make(map[string]int64),
}

func (rl *RateLimiter) isAllowed(userID, endpoint string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	key := fmt.Sprintf("%s:%s", userID, endpoint)
	rl.limits[key]++
	
	// Allow max 1000 requests per user per endpoint
	if rl.limits[key] > 1000 {
		rateLimitCounter.WithLabelValues(userID, endpoint, "request_limit").Inc()
		return false
	}
	
	return true
}

func (rl *RateLimiter) cleanup() {
	rl.mu.Lock()
	defer rl.mu.Unlock()
	
	// Cleanup old entries
	for key := range rl.limits {
		if rl.limits[key] == 0 {
			delete(rl.limits, key)
		}
	}
}

// Middleware to track requests with labels
func trackRequest(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Extract user ID from request (example: from auth header or cookie)
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = "anonymous"
		}
		
		// Extract endpoint from path
		endpoint := r.URL.Path
		
		// Extract method
		method := r.Method
		
		// Track user session
		sessionManager.trackUser(userID)
		
		// Check rate limit
		if !rateLimiter.isAllowed(userID, endpoint) {
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			return
		}
		
		// Track active requests
		activeRequests.WithLabelValues(userID, endpoint, method).Inc()
		defer activeRequests.WithLabelValues(userID, endpoint, method).Dec()
		
		// Record request duration
		start := time.Now()
		
		// Wrap response writer to capture status code
		wrapper := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}
		
		// Call next handler
		next(wrapper, r)
		
		// Record metrics
		duration := time.Since(start).Seconds()
		statusCode := fmt.Sprintf("%d", wrapper.statusCode)
		
		requestCounter.WithLabelValues(userID, endpoint, method, statusCode).Inc()
		requestDuration.WithLabelValues(userID, endpoint, method).Observe(duration)
		
		// Update cardinality tracking
		cardinalityTracker.WithLabelValues("http_requests_total").Set(float64(sessionManager.getActiveUserCount()))
	}
}

// responseWriter wraps http.ResponseWriter to capture status code
type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

